import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, Button, AsyncStorage } from 'react-native';

const AuthContext = React.createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loadUserData = async () => {
      const userData = await AsyncStorage.getItem('userData');
      if (userData) {
        setUser(JSON.parse(userData));
      }
    };
    loadUserData();
  }, []);

  const signIn = async (token, userData) => {
    await AsyncStorage.setItem('userData', JSON.stringify(userData));
    await AsyncStorage.setItem('authToken', token);
    setUser(userData);
  };

  const signOut = async () => {
    await AsyncStorage.removeItem('userData');
    await AsyncStorage.removeItem('authToken');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, signIn, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

const LoginScreen = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { signIn } = React.useContext(AuthContext);

  const handleLogin = async () => {
    // replace with actual API call
    const response = await fakeApiLogin(email, password);
    if (response.token) {
      signIn(response.token, response.userData);
    }
  };

  return (
    <View>
      <Text>Login</Text>
      <TextInput
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
      />
      <TextInput
        placeholder="Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />
      <Button title="Login" onPress={handleLogin} />
    </View>
  );
};

const App = () => {
  return (
    <AuthProvider>
      <LoginScreen />
      {/* Other components can access AuthContext here */}
    </AuthProvider>
  );
};

// Fake API login function for demonstration
const fakeApiLogin = (email, password) => {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({
        token: 'fake_auth_token',
        userData: { email: email },
      });
    }, 1000);
  });
};

export default App;